const body = $input.first().json.body ?? $input.first().json;
const { seq_step_id, sequence_id, cancel_appointment = false, cascade_mode = 'none', cascade_days = 0, notify_patient = false } = body;

if (!seq_step_id)  throw new Error('seq_step_id is required');
if (!sequence_id)  throw new Error('sequence_id is required');

const cascadeDays = parseInt(cascade_days, 10) || 0;
const doCascade   = cascade_mode === 'shift_all' && cascadeDays !== 0;

return [{ json: {
  seq_step_id:        parseInt(seq_step_id, 10),
  sequence_id:        parseInt(sequence_id, 10),
  cancel_appointment: !!cancel_appointment,
  cascade_days:       cascadeDays,
  cascade_mode,
  doCascade,
  notify_patient:     !!notify_patient,
} }];

