-- Cancel linked appointment if requested
DO $$
DECLARE v_appt_id UUID;
BEGIN
  SELECT appointment_id INTO v_appt_id FROM treatment_seq_steps WHERE id = {{ $json.seq_step_id }};
  IF {{ $json.cancel_appointment }} AND v_appt_id IS NOT NULL THEN
    UPDATE appointments
    SET status = 'cancelled', updated_at = NOW()
    WHERE id = v_appt_id;
  END IF;
END $$;

-- Get step_position before deleting
SELECT step_position FROM treatment_seq_steps WHERE id = {{ $json.seq_step_id }}

